 3166: static void check_buffer_tree_ref(struct extent_buffer *eb)
 3167: {
 3168: 	int refs;
 3169: 	/*
 3170: 	 * The TREE_REF bit is first set when the extent_buffer is added to the
 3171: 	 * xarray. It is also reset, if unset, when a new reference is created
 3172: 	 * by find_extent_buffer.
 3173: 	 *
 3174: 	 * It is only cleared in two cases: freeing the last non-tree
 3175: 	 * reference to the extent_buffer when its STALE bit is set or
 3176: 	 * calling release_folio when the tree reference is the only reference.
 3177: 	 *
 3178: 	 * In both cases, care is taken to ensure that the extent_buffer's
 3179: 	 * pages are not under io. However, release_folio can be concurrently
 3180: 	 * called with creating new references, which is prone to race
 3181: 	 * conditions between the calls to check_buffer_tree_ref in those
 3182: 	 * codepaths and clearing TREE_REF in try_release_extent_buffer.
 3183: 	 *
 3184: 	 * The actual lifetime of the extent_buffer in the xarray is adequately
 3185: 	 * protected by the refcount, but the TREE_REF bit and its corresponding
 3186: 	 * reference are not. To protect against this class of races, we call
 3187: 	 * check_buffer_tree_ref() from the code paths which trigger io. Note that
 3188: 	 * once io is initiated, TREE_REF can no longer be cleared, so that is
 3189: 	 * the moment at which any such race is best fixed.
 3190: 	 */
 3191: 	refs = refcount_read(&eb->refs);
 3192: 	if (refs >= 2 && test_bit(EXTENT_BUFFER_TREE_REF, &eb->bflags))
 3193: 		return;
 3194: 
 3195: 	spin_lock(&eb->refs_lock);
 3196: 	if (!test_and_set_bit(EXTENT_BUFFER_TREE_REF, &eb->bflags))
 3197: 		refcount_inc(&eb->refs);
 3198: 	spin_unlock(&eb->refs_lock);
 3199: }
