  490: 	unsigned int num_items = 7;
  491: 
  492: 	if (inherit) {
  493: 		/* 2 to add qgroup relations for each inherited qgroup */
  494: 		num_items += 2 * inherit->num_qgroups;
  495: 	}
  496: 	return num_items;
  497: }
